Does this work for you? We've been using this code for a long time on a high traffic site with no problems, but there may be problems/scenarios that we never encountered. The snippet simply makes use of Django's native space removal function:

from django.utils.html import strip_spaces_between_tags
class SpacelessExtension(Extension):
    tags = set(['spaceless'])
    def parse(self, parser):
        lineno = parser.stream.next().lineno
        body = parser.parse_statements(['name:endspaceless'], drop_needle=True)
        return nodes.CallBlock(self.call_method('_strip_spaces', [], [], None, None), [], [], body).set_lineno(lineno)
    def _strip_spaces(self, caller=None):
        return strip_spaces_between_tags(caller().strip())

