This "fixes" the problem I'm having, but I don't know whether it causes others.. Also see comments.

```python
def extract_raw_data_request(request):
    def _extract_raw_data_request(request):
        if request.method == 'GET':
            return request.query_string
        elif request.method == 'POST':
            if request.data:
                return request.data
            elif request.form.to_dict():
                return list(request.form.to_dict().keys())[0]
        return b('')
    raw_data = _extract_raw_data_request(request)

    tried_encodings = []

    # Try charset from content-type
    encoding = request.charset if request.charset else 'utf-8'

    if encoding:  # This will always evaluate to True since if request.charset is Falsy, encoding will become 'utf-8'
        try:
            if isinstance(raw_data, text_type):  # Potential fix?
                return raw_data
            return text_type(raw_data, encoding)
        except UnicodeError:
            tried_encodings.append(encoding)  # This doesn't get used anywhere?

    # Fall back:
    try:
        return text_type(raw_data, encoding, errors='replace')
    except TypeError:
        return raw_data
```

