Here are the details about wrapper.

```
def count_ops(func, operation_name):
    def wrapped(*args, **kwargs):
        if operation_name not in AZURE_OP_COUNT:
            AZURE_OP_COUNT[operation_name] = 0
        AZURE_OP_COUNT[operation_name] += 1
        return func(*args, **kwargs)
    return wrapped
```

```
def wrap_operations_with_retry(azure_client):
    # Wrap every method of the *Operations objects with retry logic
    for attr_name in dir(azure_client):
        if not attr_name.startswith("_"):
            attr = getattr(azure_client, attr_name)
            if attr.__class__.__name__.endswith("Operations"):
                for method_name, method in inspect.getmembers(attr, inspect.ismethod):
                    if not method_name.startswith("_"):
                        operation_name = attr.__class__.__name__ + "." + method_name
                        setattr(attr,
                                method_name,
                                retry(**default_retry_kwargs)(count_ops(method, operation_name))
                               )
```

